module top_module(
    input [1:0] logic_op_x,
    input [31:0] operand_0_x,
    input [31:0] operand_1_x,
    output [31:0] logic_result_x
);reg [31:0] obf_temp_result;

always @*
begin
    case (logic_op_x)
        2'b00: obf_temp_result = operand_0_x & operand_1_x;
        2'b01: obf_temp_result = operand_0_x | operand_1_x;
        2'b10: obf_temp_result = operand_0_x ^ operand_1_x;
        default: obf_temp_result = 0;
    endcase
end

assign logic_result_x = obf_temp_result;

endmodule
